const msg = $json.message || {};
const cb = $json.callback_query || {};
const doc = msg?.document || null;

return [{
  json: {
    chat_id: msg?.chat?.id || cb?.message?.chat?.id || null,
    input_text: (msg?.text || '').trim(),
    callback_data: cb?.data || '',
    callback_id: cb?.id || '',
    telegram_file_id: doc?.file_id || '',
    telegram_document_name: doc?.file_name || '',
    telegram_mime_type: doc?.mime_type || '',
    has_document: !!doc
  },
  binary: $binary
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
const state = states[chatId] || {};

return [{
  json: {
    ...$json,
    api_base_url: $env.N8N_API_BASE_URL || 'http://api:8000/api',
    active_case_id: state.active_case_id || '',
    pending_action: state.pending_action || ''
  },
  binary: $binary
}];

const text = ($json.input_text || '').trim();
const cb = $json.callback_data || '';
const pending = $json.pending_action || '';
const hasActive = !!$json.active_case_id;
const hasDocument = !!$json.has_document;

let route = 'UNKNOWN';
let selected_case_id = '';
let selected_doc_id = '';

if (text === '/start' || text === '/menu' || cb === 'BACK_MAIN') {
  route = 'START';
} else if (text === '/new_case' || text === '/newcase' || cb === 'MENU_NEW_CASE') {
  route = 'NEW_CASE';
} else if (pending === 'waiting_case_title' && text && !text.startsWith('/')) {
  route = 'SUBMIT_NEW_CASE';
} else if (text === '/list_cases' || text === '/listcases' || cb === 'MENU_LIST_CASES' || cb === 'CASE_LIST') {
  route = 'LIST_CASES';
} else if (cb.startsWith('CASE_SELECT:')) {
  route = 'SELECT_CASE';
  selected_case_id = cb.split(':')[1] || '';
} else if (text.startsWith('/select ')) {
  route = 'SELECT_CASE';
  selected_case_id = text.replace('/select', '').trim();
} else if (text === '/status' || cb === 'CASE_STATUS') {
  route = hasActive ? 'STATUS' : 'NO_ACTIVE_CASE';
} else if (cb === 'CASE_LIST_DOCS') {
  route = hasActive ? 'LIST_DOCS' : 'NO_ACTIVE_CASE';
} else if (cb === 'CASE_DELETE_DOC') {
  route = hasActive ? 'DELETE_DOC' : 'NO_ACTIVE_CASE';
} else if (cb.startsWith('DOC_DELETE:')) {
  route = hasActive ? 'CONFIRM_DELETE_DOC' : 'NO_ACTIVE_CASE';
  selected_doc_id = cb.split(':')[1] || '';
} else if (text === '/add_doc' || text === '/adddoc' || cb === 'CASE_ADD_DOC') {
  route = hasActive ? 'ADD_DOC' : 'NO_ACTIVE_CASE';
} else if (pending === 'waiting_document' && hasDocument) {
  route = hasActive ? 'SUBMIT_ADD_DOC' : 'NO_ACTIVE_CASE';
} else if (text === '/ask' || cb === 'CASE_ASK') {
  route = hasActive ? 'ASK' : 'NO_ACTIVE_CASE';
} else if (pending === 'waiting_question' && text && !text.startsWith('/')) {
  route = hasActive ? 'SUBMIT_ASK' : 'NO_ACTIVE_CASE';
} 

return [{
  json: {
    ...$json,
    route,
    selected_case_id,
    selected_doc_id
  },
  binary: $binary
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = states[chatId].active_case_id || '';
states[chatId].pending_action = 'waiting_case_title';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Напиши название нового дела одним сообщением', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const resp = $json;
const caseId = String(resp.case_id || resp.id || '');
const title = resp.title || $item(0).$node['Determine Route'].json.input_text || 'Без названия';
const status = resp.status || resp.case_status || 'EMPTY';
const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = caseId;
states[chatId].pending_action = '';
states[chatId].cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
const existing = states[chatId].cases.find(c => String(c.case_id || c.id || '') === caseId);
if (existing) {
  existing.title = title;
  existing.status = status;
} else {
  states[chatId].cases.unshift({ case_id: caseId, title, status, documents_count: 0 });
}
data.states = states;
return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, case_id: caseId, title, status, message_text: `Дело создано\n\n<b>${title}</b>\nID: <code>${caseId}</code>\nСтатус: ${status}`, reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],[{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],[{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],[{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const cases = Array.isArray($json.cases) ? $json.cases : [];
const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].cases = cases.map(c => ({
  case_id: String(c.case_id || c.id || ''),
  title: c.title || 'Без названия',
  status: c.status || 'UNKNOWN',
  documents_count: c.documents_count ?? null
}));
data.states = states;

if (!cases.length) {
  return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: 'У тебя пока нет дел\n\nНажми кнопку Создать дело', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Создать дело', callback_data: 'MENU_NEW_CASE' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];
}
const activeCaseId = states[chatId].active_case_id || '';
const rows = cases.map(c => {
  const id = String(c.case_id || c.id || '');
  const marker = id === activeCaseId ? '• ' : '';
  const status = c.status ? ` — ${c.status}` : '';
  return [{ text: `${marker}${(c.title || id || 'Дело').slice(0, 45)}${status}`.slice(0, 60), callback_data: `CASE_SELECT:${id}` }];
});
rows.push([{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]);
return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: 'Выбери дело', reply_markup_json: JSON.stringify({ inline_keyboard: rows }) } }];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const caseId = $item(0).$node['Determine Route'].json.selected_case_id || '';
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = caseId;
states[chatId].pending_action = '';
const cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
const selected = cases.find(c => String(c.case_id || c.id || '') === String(caseId)) || {};
data.states = states;

const title = selected.title || caseId || 'Без названия';
const status = selected.status || 'UNKNOWN';
const docsCount = selected.documents_count;
let text = `Активное дело выбрано\n\n<b>${title}</b>\nID: <code>${caseId}</code>\nСтатус: ${status}`;
if (docsCount !== undefined && docsCount !== null) text += `\nДокументов: ${docsCount}`;

return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: text, reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],[{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],[{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],[{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const status = $json.status || $json.case_status || $json.error?.code || 'UNKNOWN';
let text = `Статус дела

ID: <code>${$item(0).$node['Load State'].json.active_case_id}</code>
Статус: ${status}`;
if ($json.progress !== undefined) text += `
Прогресс: ${$json.progress}`;
if (status === 'BUILDING') text += '

Индексация еще идет';
if (status === 'DIRTY') text += '

Документы изменились, индекс устарел';
return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: text, reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }],[{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],[{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const activeCaseId = String($item(0).$node['Load State'].json.active_case_id || '');
const cases = Array.isArray(states[chatId]?.cases) ? states[chatId].cases : [];
const selected = cases.find(c => String(c.case_id || c.id || '') === activeCaseId) || {};
const title = selected.title || activeCaseId || 'Без названия';
const status = selected.status || 'UNKNOWN';
const docsCount = selected.documents_count;

let text = `Документы дела\n\n<b>${title}</b>\nID: <code>${activeCaseId}</code>\nСтатус: ${status}`;
if (docsCount !== undefined && docsCount !== null) text += `\nДокументов по списку дел: ${docsCount}`;
text += '\n\nТекущий backend в GitHub пока не отдает GET /api/cases/{case_id}, поэтому точный список документов из n8n сейчас показать нельзя.\n\nКогда команда добавит show_case, эту ветку можно будет сразу подключить.';

return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: text, reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],[{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = states[chatId].active_case_id || $json.active_case_id || '';
states[chatId].pending_action = 'waiting_document';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Теперь отправь PDF, DOCX или TXT одним сообщением', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const items = $input.all();
return items.map(item => {
  item.binary = item.binary || {};
  if (item.binary.telegram_file) {
    item.binary.telegram_file.fileName = item.json.telegram_document_name || 'document.bin';
    item.binary.telegram_file.mimeType = item.json.telegram_mime_type || item.binary.telegram_file.mimeType || 'application/octet-stream';
  }
  return item;
});

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const activeCaseId = String($item(0).$node['Load State'].json.active_case_id || '');
states[chatId] = states[chatId] || {};
states[chatId].pending_action = '';
states[chatId].cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
const selected = states[chatId].cases.find(c => String(c.case_id || c.id || '') === activeCaseId);
const ok = !!($json.doc_id || $json.id);
const status = $json.case_status || $json.status || 'DIRTY';
if (selected && ok) {
  selected.status = status;
  if (selected.documents_count !== null && selected.documents_count !== undefined) {
    selected.documents_count = Number(selected.documents_count) + 1;
  }
}
data.states = states;
const text = ok ? `Документ загружен\n\n${$json.name || $item(0).$node['Prepare Telegram File Path'].json.telegram_document_name}\nСтатус дела: ${status}` : `Не удалось загрузить документ\n\n${$json.error?.message || 'Проверь multipart upload в n8n и маршрут /api/cases/:case_id/documents'}`;
return [{ json: { chat_id: $item(0).$node['Load State'].json.chat_id, message_text: text, reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].pending_action = '';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Сценарий ask пока отключен\n\nВ текущем GitHub еще нет POST /api/cases/{case_id}/ask, поэтому вопрос по делу из n8n сейчас нельзя отправить честно и стабильно.', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].pending_action = '';
data.states = states;
return [{ json: { placeholder: true } }];
